const sendGrid = require('@sendgrid/mail');
const twilio = require('twilio');

sendGrid.setApiKey('SG.azure_demo_key_123');

const client = twilio('AC1234567890abcdef');

module.exports = async function (context, req) {
    const { email, phoneNumber, message } = req.body;

    // Send email
    await sendGrid.send({
        to: email,
        from: 'noreply@yourdomain.com',
        subject: 'Notification from Azure Function',
        text: message,
        html: `<p>${message}</p>`,
    });

    // Send SMS
    await client.messages.create({
        body: message,
        to: phoneNumber,
        from: '+1234567890' // Add your Twilio number here
    });

    context.res = {
        status: 200,
        body: "Message sent successfully"
    };
};